# Category: sql_injection

class User < ApplicationRecord
  # SAFE: Uses parameterized query to prevent SQL injection
  def self.search_by_email_domain(domain)
    # Sanitize and validate the domain input
    raise ArgumentError, "Domain cannot be blank" if domain.blank?
    raise ArgumentError, "Invalid domain format" unless domain.match?(/\A[a-zA-Z0-9][a-zA-Z0-9\-\.]*\.[a-zA-Z]{2,}\z/)

    # Use parameterized query with find_by_sql to prevent SQL injection
    find_by_sql(["SELECT * FROM users WHERE email LIKE ?", "%@#{sanitize_sql_like(domain)}"])
  end

